import { Kernel } from '@semantic-kernel/core';
import { VexClient } from 'vex-sdk';

const kernel = new Kernel();
const vex = new VexClient({ apiKey: 'your-vex-key' });

// Add HR plugins
kernel.importPluginFromObject(resumeParser);
kernel.importPluginFromObject(biasChecker);

kernel.setExecutionFilter(async (context, next) => {
  const plan = context.getValue('plan');

  const verdict = await vex.check({
    input: JSON.stringify(plan),
    category: 'hr-planner',
    regulations: ['nyc-ll144', 'eu-ai-act']
  });

  if (verdict.risk === 'critical') {
    context.setValue('result', 'BLOCKED: Invalid plan - missing bias audit step');
    return;
  }

  await next();
});

